
<template>
    <div class="layout gutter--sm" v-if="!gameEndChecker">
        <template v-if="currentQUizs.length > 0">
            <div
                v-for="(quiz,idx) in currentQUizs"
                :key="'quiz' + idx"
                class="row"
                style="padding:4px;"
            >
                <template v-if="idx < currentFocus + 10 && idx > currentFocus - 10">
                    <div class="flex xs12 lg8 offset--lg2" :ref="setFocusRef" :data-idx="idx">
                        <va-button
                            block
                            class="mr-2"
                            color="secondary"
                            :outline="QuizsAnswerStatus[idx].checker === null"
                            style="padding:5px;"
                            :rounded="false"
                            @click="howl.play(quiz.answer)"
                        >
                            <span :class="dWidth ? 'question_big mx-3' : 'question mx-3'">
                                {{ QuizsAnswerStatus[idx].checker !== null ? "已作答" : "" }}
                                {{ idx + 1 }}.
                                {{ quiz.quiz }}
                            </span>
                            <span :class="dWidth ? 'question_big mx-3 code' : 'question mx-3 code'">
                                {{
                                    quiz.answer.split("").map((e, idx) => {
                                        if (idx !== 0 && (quiz.answer.length > 3 ? (idx !== quiz.answer.length - 1) : true)) {
                                            switch (e) {
                                                case " ":
                                                    return " ";
                                                case "-":
                                                    return "-";
                                                case ".":
                                                    return ".";
                                                case "'":
                                                    return "'";
                                                default:
                                                    return "◻︎";
                                            }
                                        } else {
                                            return e
                                        }
                                    }).join("")
                                }}
                            </span>
                            <va-icon size="large" name="record_voice_over" />
                        </va-button>
                    </div>
                    <div class="flex xs6 lg4 offset--lg2">
                        <input
                            block
                            class="form_input"
                            spellcheck="false"
                            autocomplete="off"
                            autocorrect="off"
                            inputmode="email"
                            :disabled="!ConnectionChecker"
                            :loading="!ConnectionChecker"
                            v-model="QuizsAnswerStatus[idx].ans"
                            @focus="() => currentFocus = idx"
                            @keyup.enter="enterSubmit(idx, QuizsAnswerStatus[idx].ans)"
                            @keyup.up="focus('up', idx)"
                            @keyup.down="focus('down', idx)"
                            @keydown.tab.prevent="howl.play(quiz.answer)"
                            :ref="setQuizRef"
                        />
                    </div>
                    <div class="flex xs6 lg4 mb-8">
                        <va-button
                            color="secondary"
                            block
                            :disabled="!ConnectionChecker"
                            :loading="!ConnectionChecker"
                            @click="enterSubmit(idx, QuizsAnswerStatus[idx].ans)"
                        >送出答案</va-button>
                    </div>
                    <div class="flex xs12">
                        <va-divider />
                    </div>
                </template>
            </div>
        </template>
    </div>
    <div class="layout gutter--sm" v-else>
        <div class="row" v-if="currentQUizs.length > 0" style="padding:4px;">
            <template v-for="(quiz,idx) in currentQUizs" :key="'quiz' + idx">
                <div class="flex xs12 lg8 offset--lg2">
                    <va-button
                        block
                        class="mr-2"
                        :color="
                            QuizsAnswerStatus[idx]?.checker !== null ?
                                QuizsAnswerStatus[idx].checker ?
                                    'success' : 'danger' : 'secondary'
                        "
                        :outline="QuizsAnswerStatus[idx].checker === null"
                        style="padding:5px;"
                        :rounded="false"
                        @click="howl.play(quiz.answer)"
                    >
                        <span :class="dWidth ? 'question_big mx-3' : 'question mx-3'">
                            {{
                                QuizsAnswerStatus[idx].checker !== null ?
                                    QuizsAnswerStatus[idx].checker ? "正確" : "錯誤" : "沒作答"
                            }}
                            {{ idx + 1 }}.
                            {{ quiz.quiz }}
                        </span>
                        <va-icon size="large" name="record_voice_over" />
                    </va-button>
                </div>
                <div class="flex xs6 lg4 offset--lg2">你的答案：{{ QuizsAnswerStatus[idx].ans }}</div>
                <div class="flex xs6 lg4 mb-8">正確答案：{{ QuizsAnswerStatus[idx].correct_ans }}</div>
                <div class="flex xs12">
                    <va-divider />
                </div>
            </template>
        </div>
    </div>
</template>

<script setup>
import { ref, onUpdated, onBeforeUpdate, onMounted, watch, computed } from "vue";
import { useGameLogics } from "../compositions/useGameLogics";
import { useWSConnection } from "../compositions/useWSConnection";
import WindowInstanceMap from "../lib/vuejs-usewiindohw";
import { useHowl } from "../compositions/useHolwer";
const { howl } = useHowl();
const dWidth = computed(() => WindowInstanceMap.innerWidth > 720);
const { ConnectionChecker } = useWSConnection();
const {
    currentQUizs,
    SubmitAns,
    QuizsAnswerStatus,
    currentRecord,
} = useGameLogics();


const quizsRefs = [];
const focusRefs = [];
const currentFocus = ref(QuizsAnswerStatus.value.findIndex(e => e.checker === null));

watch(currentFocus, () => {
    howl.play(currentQUizs.value[currentFocus.value].answer);
});

const setQuizRef = (el) => {
    quizsRefs.push(el);
};
const setFocusRef = (el) => {
    focusRefs.push(el);
};
onBeforeUpdate(() => {
    quizsRefs.splice(0, quizsRefs.length);
    focusRefs.splice(0, focusRefs.length);
});

var preIdx = null
onUpdated(() => {
    if (preIdx === currentFocus.value) {
        return;
    }
    preIdx = currentFocus.value;
    let refIdx = focusRefs.findIndex(e => e?.dataset?.idx == currentFocus.value);
    if (refIdx === -1) return;
    quizsRefs[refIdx].focus();
    focusRefs[refIdx].scrollIntoView({
        behavior: "smooth",
        block: "center",
    });
});
onMounted(() => {
    if (!gameEndChecker.value) {
        let refIdx = focusRefs.findIndex(e => e.dataset.idx == currentFocus.value);
        if (refIdx === -1) return;
        quizsRefs[refIdx].focus();
        focusRefs[refIdx].scrollIntoView({
            behavior: "smooth",
            block: "center",
        });
    }
});

const focus = (direction, idx) => {
    if (direction === "up") {
        currentFocus.value = idx - 1;
    }
    else {
        currentFocus.value = idx + 1;
    }
}

const enterSubmit = (idx, ans) => {
    if (ans !== null) {
        SubmitAns(idx, ans);
    }
    focus("down", idx);
};

const gameEndChecker = ref(
    currentRecord.value.game_result.game_ended ||
    new Date(currentRecord.value.game.time_limit) < new Date()
);



</script>
<style scoped>
.white {
    color: white;
}
.code {
    font-family: monospace;
}

.question {
    font-size: 1rem;
    padding: 2px;
    line-height: normal;
}

.question_big {
    font-size: 2rem;
    padding: 2px;
    line-height: normal;
}

.form_input {
    font-family: "Roboto", sans-serif;
    color: #333;
    font-size: 1rem;
    margin: auto;
    padding: 3px;
    border-radius: 0.2rem;
    background-color: rgb(255, 255, 255);
    width: 90%;
    display: block;
    transition: all 0.3s;
}
</style>
