import { reactive, ref } from "vue";
// import { decode,encode } from "../lib/cbor";
import { decode, encode } from "cbor-x";

const defaultToken = "";

const Token = ref(defaultToken);
const WSConnector = reactive({});
const HOST = "wss://ams.boyo.org.tw/socket.io";
const ConnectionChecker = ref(false);
const currentOnMessage = ref(false);
const messageReceived = ref([]);
const KeepAliveTimer = ref(null);
const disConnectMessage = ref(null);

export function useWSConnection() {
    const setToken = (token) => changeTokenR(token);
    const connectWS = connectWSR;
    const setOnMessage = setOnMessageR;
    const disconnectWS = disconnectWSR;
    const getMessages = getMessagesR;
    const setOnClose = setOnCloseR;
    const sendMessage = (message) => {
        if (ConnectionChecker.value === false)
            throw new Error("Connection is not established");
        if (WSConnector.ws.readyState !== WSConnector.ws.OPEN) {
            throw new Error("Connection is not established");
        }
        let json_string = encode(message);
        WSConnector.ws.send(json_string);
    };

    const getToken = () => Token.value;
    return {
        ConnectionChecker,
        WSConnector,
        disConnectMessage,
        setOnClose,
        getMessages,
        sendMessage,
        setToken,
        connectWS,
        setOnMessage,
        disconnectWS,
        getToken,
    };
}

const getMessagesR = () => {
    return messageReceived.value;
}

const changeTokenR = (token) => {
    Token.value = token;
};

const disconnectWSR = () => {
    WSConnector.ws.onclose = null;
    ConnectionChecker.value = false;
    WSConnector.ws.close();
};

const localSetOnMessage = (callback, event) => {
    let data;
    if (event.data instanceof ArrayBuffer) {
        let u8array = new Uint8Array(event.data);
        data = decode(u8array);
    } else {
        data = event.data;
        data = JSON.parse(data);
    }
    messageReceived.value.push(data);
    if (typeof callback === "function") {
        return callback(data);
    } else {
        return data;
    }
};

const setOnMessageR = (callback) => {
    if (WSConnector.ws !== undefined) {
        WSConnector.ws.onmessage = (event) => {
            localSetOnMessage(callback, event);
        };
    }
    currentOnMessage.value = callback;
};

const localOnClose = {
    callBack: () => { },
};

const setOnCloseR = (callback) => {
    localOnClose.callBack = callback;
};

const connectWSR = async () => {
    disConnectMessage.value = null;
    clearInterval(KeepAliveTimer.value);
    KeepAliveTimer.value = null;
    WSConnector.ws = new WebSocket(HOST + `/${Token.value}`);
    WSConnector.ws.binaryType = "arraybuffer";
    WSConnector.ws.onmessage = (event) => {
        localSetOnMessage(currentOnMessage.value, event);
    };
    WSConnector.ws.onclose = async (event) => {
        if (event.code === 4000 && event.reason === "登入認證失效") {
            WSConnector.ws.onclose = null;
            ConnectionChecker.value = false;
            Token.value = null;
            localOnClose.callBack();
            clearInterval(KeepAliveTimer.value);
            KeepAliveTimer.value = null;
            disConnectMessage.value = event.reason;
            return;
        } else {
            disConnectMessage.value = "系統斷線！請重新登入！";
            WSConnector.ws.onclose = null;
            ConnectionChecker.value = false;
            Token.value = null;
            localOnClose.callBack();
            clearInterval(KeepAliveTimer.value);
            KeepAliveTimer.value = null;
            return;
        }
    };

    return new Promise((resolve) => {
        WSConnector.ws.onopen = () => {
            console.log("WS Connected");
            ConnectionChecker.value = true;
            KeepAliveTimer.value = setInterval(() => {
                try {
                    WSConnector.ws.send(encode({ ping: true }));
                } catch (err) {
                    console.log(err);
                    clearInterval(KeepAliveTimer.value);
                }
            }, 5000);
            resolve(true);
        };
    });
};
