import { Howl } from 'howler';
import howlsetting from "../assets/VB.json";
import {reactive,ref} from "vue";

const howl = reactive(new Howl(howlsetting));
const loaded = ref(false);

howl.once("load",()=>{
    loaded.value = true;
});

export function useHowl(){
    return {
        howl,
        loaded
    }
}